const fs = require('fs');
const f = fs.readFileSync('index.ts','utf8');
// Check BakeWidget class
if (f.includes('private renderCount = 0')) console.log('OK: renderCount field');
if (f.includes('this.renderCount++')) console.log('OK: renderCount increment');
if (!f.includes('startSpinner') && !f.includes('stopSpinner') && !f.includes('SPINNER_FRAMES')) console.log('OK: spinner code removed');
if (!f.includes('setWorkingIndicator') && !f.includes('setWorkingMessage')) console.log('OK: no working indicator overrides');
if (f.includes('bakeCtx.bake.onStateChange')) console.log('OK: state change handler preserved');
console.log('---');
const d = fs.readFileSync('commands/detail.ts','utf8');
if (d.includes('buildBody')) console.log('OK: buildBody exists');
if (!d.includes('new Container') && !d.includes('new Text') && !d.includes('new Spacer')) console.log('OK: no Container/Text/Spacer in detail.ts');
if (d.includes(': string[] =>')) console.log('OK: buildBody returns string[]');
console.log('---');
// Check dead files removed
['components/loader.ts','components/anim.ts','lib/overlay.ts'].forEach(p => {
  try { fs.accessSync(p); console.log('WARNING: ' + p + ' still exists'); }
  catch { console.log('OK: ' + p + ' removed'); }
});
"

